// ── Factory function ──────────────────────────────────────────────────────────
// Creates the expanded ADAU1466 3-way registry from the embedded CSV.
// Master Volume L (0x0067) and R (0x0064) are promoted to verified/directWriteValidated.
// All other extracted addresses remain exportConfirmed or needsLiveValidation.

DspAddressRegistry createTunaiAdau1466ThreeWayRegistry() {
  final importer = ProAddressMapImporter();
  final result = importer.parseOperationalCsv(kTunaiAdau1466ThreeWayAddressMapCsv);
  return result.registry.copyWith(
    revision: 2,
    peqRowCount: kTunaiAdau1466ThreeWayPeqRowCount,
    peqStatus: DspAddressVerificationStatus.exportConfirmed,
    updatedAt: DateTime.utc(2026, 7, 10),
  );
}
